@ARTICLE{10.1097/MAT.0000000000001528,
	author = {Packer EJS and Solholm A and Omdal TR and Stangeland L and Zhang L and Mongstad A and Urban M and Wentzel-Larsen T and Haaverstad R and Slettom G and Nordrehaug JE and Grong K and Tuseth V},
	title = {Effects of Add-On Left Ventricular Assist Device to Extracorporeal Membrane Oxygenation During Refractory Cardiac Arrest in a Porcine Model.},
	journal = {ASAIO J},
	year = {2022},
	abstract = {This study evaluated the effects of extracorporeal membrane oxygenation (ECMO) in combination with a percutaneous adjunctive left ventricular assist device (LVAD) in a porcine model during 60 minutes of refractory cardiac arrest (CA). Twenty-four anesthetized swine were randomly allocated into three groups given different modes of circulatory assist: group 1: ECMO 72 ml/kg/min and LVAD; group 2: ECMO 36 ml/kg/min and LVAD; and group 3: ECMO 72 ml/kg/min. During CA and extracorporeal cardiopulmonary resuscitation (ECPR), mean left ventricular pressure (mLVP) was lower in group 1 (p = 0.013) and in group 2 (p = 0.003) versus group 3. Mean aortic pressure (mAP) and coronary perfusion pressure (CPP) were higher in group 1 compared with the other groups. In group 3, mean pulmonary artery flow (mPAf) was lower versus group 1 (p = 0.003) and group 2 (p = 0.039). If the return of spontaneous circulation (ROSC) was achieved after defibrillation, up to 180 minutes of unsupported observation followed. All subjects in groups 1 and 3, and 5 subjects in group 2 had ROSC. All subjects in group 1, five in group 2 and four in group 3 had sustained cardiac function after 3 hours of spontaneous circulation. Subjects that did not achieve ROSC or maintained cardiac function post-ROSC had lower mAP (p < 0.001), CPP (p = 0.002), and mPAf (p = 0.004) during CA and ECPR. Add-on LVAD may improve hemodynamics compared with ECMO alone during refractory CA but could not substitute reduced ECMO flow. Increased mAP and CPP could be related to ROSC rate and sustained cardiac function. Increased mLVP was related to poor post-ROSC cardiac function.},
	doi = {10.1097/MAT.0000000000001528},
	pmid = {34294641 [Indexed for MEDLINE]}
}

@ARTICLE{10.1097/MAT.0000000000001419,
	author = {Swan JT and Iso T and Rizk E and Trachtenberg BH and Krisl J and Varnado S and Suki WN and Frost AE and Suarez E and Uddin FS and Kassi M and Giesecke NM and Bhimaraj A and Masud FN},
	title = {Defining Vasoplegia Following Durable, Continuous Flow Left Ventricular Assist Device Implantation.},
	journal = {ASAIO J},
	year = {2022},
	abstract = {This study aimed to develop a definition of vasoplegia that reliably predicts clinical outcomes. Vasoplegia was evaluated using data from the electronic health record for each 15-minute interval for 72 hours following cardiopulmonary bypass. Standardized definitions considered clinical features (systemic vascular resistance [SVR], mean arterial pressure [MAP], cardiac index [CI], norepinephrine equivalents [NEE]), threshold strategy (criteria occurring in any versus all measurements in an interval), and duration (criteria occurring over multiple consecutive versus separated intervals). Minor vasoplegia was MAP < 60 mm Hg or SVR < 800 dynes⋅sec⋅cm-5 with CI > 2.2 L/min/m2 and NEE ≥ 0.1 μg/kg/min. Major vasoplegia was MAP < 60 mm Hg or SVR < 700 dynes⋅sec⋅cm-5 with CI > 2.5 L/min/m2 and NEE ≥ 0.2 μg/kg/min. The primary outcome was incidence of vasoplegia for eight definitions developed utilizing combinations of these criteria. Secondary outcomes were associations between vasoplegia definitions and three clinical outcomes: time to extubation, time to intensive care unit discharge, and nonfavorable discharge. Minor vasoplegia detected anytime within a 15-minute period (MINOR_ANY_15) predicted the highest incidence of vasoplegia (61%) and was associated with two of three clinical outcomes: 1 day delay to first extubation (95% CI: 0.2 to 2) and 7 day delay to first intensive care unit discharge (95% CI: 1 to 13). The MINOR_ANY_15 definition should be externally validated as an optimal definition of vasoplegia.},
	doi = {10.1097/MAT.0000000000001419},
	pmid = {34227791 [Indexed for MEDLINE]}
}

@ARTICLE{10.1097/MAT.0000000000001497,
	author = {Cowger JA and Estep JD and Rinde-Hoffman DA and Givertz MM and Anderson AS and Jacoby D and Chen L and Brieke A and Mahr C and Hall S and Ewald GA and Dirckx N and Baker AT and Pinney SP},
	title = {Variability in Blood Pressure Assessment in Patients Supported with the HeartMate 3TM.},
	journal = {ASAIO J},
	year = {2022},
	abstract = {Targeted blood pressure (BP) control is a goal of left ventricular assist device medical management, but the interpretation of values obtained from noninvasive instruments is challenging. In the MOMENTUM 3 Continued Access Protocol, paired BP values in HeartMate 3 (HM3) patients were compared from arterial (A)-line and Doppler opening pressure (DOP) (319 readings in 261 patients) and A-line and automated cuff (281 readings in 247 patients). Pearson (R) correlations between A-line mean arterial (MAP) and systolic blood pressures (SBP) were compared with DOP and cuff measures according to the presence (>1 pulse in 5 seconds) or absence of a palpable radial pulse. There were only moderate correlations between A-line and noninvasive measurements of SBP (DOP R = 0.58; cuff R = 0.47) and MAP (DOP R = 0.48; cuff R = 0.37). DOP accuracy for MAP estimation, defined as the % of readings within ± 10 mmHg of A-line MAP, decreased from 80% to 33% for DOP ≤ 90 vs. >90 mmHg, and precision also diminished (mean absolute difference [MAD] increased from 6.3 ± 5.6 to 16.1 ± 11.4 mmHg). Across pulse pressures, cuff MAPs were within ±10 mmHg of A-line 62.9%-68.8% of measures and MADs were negligible. The presence of a palpable pulse reduced the accuracy and precision of the DOP-MAP estimation but did not impact cuff-MAP accuracy or precision. In summary, DOP may overestimate MAP in some patients on HM3 support. Simultaneous use of DOP and automated cuff and radial pulse may be needed to guide antihypertensive medication titration in outpatients on HM3 support.},
	doi = {10.1097/MAT.0000000000001497},
	pmid = {34172641 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/jocs.15564,
	author = {Montalto A and Amarelli C and Piazza V and Hopkins K and Comisso M and Pantanella R and Musumeci F},
	title = {A new hemodynamic index to predict late right failure in patients implanted with last generation centrifugal pump.},
	abstract = {BACKGROUND: Right ventricular failure (RVF) is a severe event that increases perioperative mortality after left ventricle assist device (LVAD) implantation. Right ventricular (RV) function is particularly affected by the LVAD speed by altering RV preload and afterload as well as the position of the interventricular septum. However, there are no studies focusing on the relationship between pump speed optimization and risk factors for the development of late RVF. METHODS: Between 2015 and 2019, 50 patients received LVAD implantation at San Camillo Hospital in Rome. Of these, 38 who underwent pump speed optimization were included. Post-optimization hemodynamic data were collected. We assessed a new Hemodynamic Index (HI), calculated as follows: HI = MAP × / × / , to determine the risk of late RVF, which was defined as the requirement for rehospitalization and inotropic support. RESULTS: Ten patients had late RVF after LVAD implantation. Five patients required diuretic therapy and speed optimization. Three patients required inotropic support with adrenaline 0.05 μg/kg/min. Two patients needed prolonged continuous venovenous hemofiltration and high dose inotropic support. Multivariate analysis revealed that a low HI (odds ratio 11.5, 95% confidence interval, 1.85-65.5, p [.003]) was an independent risk factor for late RVF after LVAD implantation. CONCLUSION: We demonstrated a low HI being a significant risk factor for the development of RVF after LVAD implantation. We suggest implementing HI as a decision support tool for goal-direct optimization of the device aiming to reduce the burden of late-onset RVF during the follow-up.},
	doi = {10.1111/jocs.15564},
	pmid = {33870583 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/ehjci/jeab057,
	author = {Skjølsvik ET and Haugen Lie Ø and Chivulescu M and Ribe M and Castrini AI and Broch K and Pripp AH and Edvardsen T and Haugaa KH},
	title = {Progression of cardiac disease in patients with lamin A/C mutations.},
	journal = {Eur Heart J Cardiovasc Imaging},
	year = {2022},
	abstract = {AIMS: We aimed to study the progression of cardiac dysfunction in patients with lamin A/C mutations and explore markers of adverse cardiac outcome. METHODS AND RESULTS: We followed consecutive lamin A/C genotype-positive patients divided into tertiles according to age. Patients underwent repeated clinical examinations, electrocardiograms (ECGs), and echocardiograms. We followed left ventricular (LV) and right ventricular (RV) size and function, and the severity atrioventricular-valve regurgitations. Outcome was death, LVAD implant, or cardiac transplantation. We included 101 patients [age 44 (29-54) years, 39% probands, 50% female]. We analysed 576 echocardiograms and 258 ECGs during a follow-up of 4.9 (interquartile range 2.5-8.2) years. The PR-interval increased at young age from 204 ± 73 to 212 ± 69 ms (P < 0.001), LV ejection fraction (LVEF) declined from middle age from 50 ± 12% to 47 ± 13% (P < 0.001), while LV volumes remained unchanged. RV function and tricuspid regurgitation worsened from middle age with accelerating rates. Progression of RV dysfunction [odds ratio (OR) 1.3, 95% confidence interval (CI) (1.03-1.65), P = 0.03] and tricuspid regurgitation [OR 4.9, 95% CI (1.64-14.9), P = 0.004] were associated with outcome when adjusted for age, sex, comorbidities, LVEF, and New York Heart Association functional class. CONCLUSION: In patients with lamin A/C genotype, electrical disease started at young age. From middle age, LV function deteriorated progressively, while LV size remained unchanged. Worsening of RV function and tricuspid regurgitation accelerated in older age and were associated with outcome. Our systematic map on cardiac deterioration may help optimal monitoring and prognostication in lamin A/C disease.},
	doi = {10.1093/ehjci/jeab057},
	pmid = {33824984 [Indexed for MEDLINE]},
	note = {PMC8944327}
}

