@ARTICLE{10.1097/MAT.0000000000001158,
	author = {Rossini L and Braun OÖ and Brambatti M and Benito Y and Mizeracki A and Miramontes M and Nguyen C and Martinez-Legazpi P and Almeida S and Kraushaar M and Vu V and May-Newman K and Bermejo J and Adler ED and Kahn AM and Del Alamo JC},
	title = {Intraventricular Flow Patterns in Patients Treated with Left Ventricular Assist Devices.},
	journal = {ASAIO J},
	year = {2021},
	abstract = {The success of left ventricular assist device (LVAD) therapy is hampered by complications such as thrombosis and bleeding. Understanding blood flow interactions between the heart and the LVAD might help optimize treatment and decrease complication rates. We hypothesized that LVADs modify shear stresses and blood transit in the left ventricle (LV) by changing flow patterns and that these changes can be characterized using 2D echo color Doppler velocimetry (echo-CDV). We used echo-CDV and custom postprocessing methods to map blood flow inside the LV in patients with ongoing LVAD support (Heartmate II, N = 7). We compared it to healthy controls (N = 20) and patients with dilated cardiomyopathy (DCM, N = 20). We also analyzed intraventricular flow changes during LVAD ramp tests (baseline ± 400 rpm). LVAD support reversed the increase in blood stasis associated with DCM, but it did not reduce intraventricular shear exposure. Within the narrow range studied, the ventricular flow was mostly insensitive to changes in pump speed. Patients with significant aortic insufficiency showed abnormalities in blood stasis and shear indices. Overall, this study suggests that noninvasive flow imaging could potentially be used in combination with standard clinical methods for adjusting LVAD settings to optimize flow transport and minimize stasis on an individual basis.},
	doi = {10.1097/MAT.0000000000001158},
	pmid = {33346993 [Indexed for MEDLINE]}
}

@ARTICLE{10.1097/MAT.0000000000001257,
	author = {Kado Y and Polakowski AR and Kuban BD and Horvath DJ and Miyamoto T and Karimov JH and Starling RC and Fukamachi K},
	title = {The Effects of Preserving Mitral Valve Function on a Left Atrial Assist Device: An In Vitro Mock Circulation Loop Study.},
	journal = {ASAIO J},
	year = {2021},
	abstract = {We are developing a left atrial assist device (LAAD) to pump blood from the left atrium to the left ventricle for patients who have heart failure with preserved ejection fraction (HFpEF). This study aimed to assess the hemodynamics with the LAAD implanted at two different levels: the mitral valve (MV) level, after removing the MV; and the supravalvular level, preserving MV function conditions using an in vitro mock circulatory loop. Normal heart and mild, moderate, and severe diastolic heart failure conditions were simulated, and the LAAD was set at three different speeds. Without the LAAD support, cardiac output (CO) decreased from 3.7 to 1.1 L/min, aortic pressure (AoP) decreased from 100 to 33 mm Hg, and left atrial pressure (LAP) increased from 16 to 23 mm Hg as the diastolic function became impaired. With high pump support after removing the MV, CO and AoP readings were comparable with those for preserved MV function (CO reached 3.9-4.1 L/min, AoP reached more than 110 mm Hg, and LAP dropped to 16-17 mm Hg under both conditions at high pump speeds). In the mock circulatory loop, our LAAD appeared to have sufficient ability to maintain the hemodynamic status at both positions.},
	doi = {10.1097/MAT.0000000000001257},
	pmid = {32897890 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.athoracsur.2020.05.172,
	author = {Saha A and Jennings DL and Ning Y and Kurlansky P and Miltiades AN and Spellman JL and Sanchez J and Yuzefpolskaya M and Colombo PC and Takayama H and Naka Y and Takeda K},
	title = {Methylene Blue Does Not Improve Vasoplegia After Left Ventricular Assist Device Implantation.},
	journal = {Ann Thorac Surg},
	year = {2021},
	abstract = {BACKGROUND: Vasoplegia is a frequent complication of left ventricular assist device (LVAD) implantation. We investigated the effectiveness of methylene blue (MB) for vasoplegia in LVAD recipients. METHODS: Twenty-seven patients received MB for vasoplegia after LVAD implantation and met study criteria between March 2015 and May 2018. Propensity score inverse probability weighting identified 41 controls who did not receive MB for post-LVAD vasoplegia. Clinical outcomes were compared between control and MB groups and between patients who received doses during (n = 15) and after surgery (n = 12). Hemodynamics and vasopressor requirements were analyzed using analysis of covariance. RESULTS: Median total MB dose was 1.9 mg/kg (interquartile range, 1.2-2.2 mg/kg). Methylene blue recipients experienced a transient initial decline in norepinephrine requirement from 141 ng/kg per min (95% confidence interval [CI], 81-201 ng/kg per min) to 117 ng/kg per min (95% CI, 58-176 ng/kg per min; P = .022) and a delayed decline in vasopressin from 4.8 U/h (95% CI, 3.8-5.8 U/h) to 4.0 U/h (95% CI, 2.8-5.1 U/h) (P = .004). In-hospital mortality, postoperative complications, and end-organ dysfunction did not differ from those of controls. There were no observed differences in mean arterial pressure, vasopressor requirements, or outcomes between patients who received doses during or after surgery. Weighted overall mortality in the entire study cohort was 8.8%. CONCLUSIONS: Although MB may affect vasopressor requirements, clinical outcomes in vasoplegia after LVAD implantation did not improve and were not affected by the timing of administration.},
	doi = {10.1016/j.athoracsur.2020.05.172},
	pmid = {32758558 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s10741-020-10006-4,
	author = {Alvarez PA and Ponnapureddy R and Voruganti D and Duque ER and Briasoulis A},
	title = {Noninvasive measurement of arterial blood pressure in patients with continuous-flow left ventricular assist devices: a systematic review.},
	journal = {Heart Fail Rev},
	year = {2021},
	abstract = {Accurate mean blood pressure determination is essential to prevent adverse events in patients with continuous-flow left ventricular assist devices (CFLVAD). We sought to evaluate the accuracy of noninvasive methods of blood pressure measurement compared with invasive intra-arterial recordings in patients with CFLVAD. Systematic electronic search was performed on four online databases (PubMed, Scopus, Embase, and Web of Knowledge) for the terms "Blood Pressure" AND ("Heart-Assist Devices" OR "Left ventricular Assist Devices"). Only studies that compared an intra-arterial and noninvasive blood pressure measurement were included. Electronic search of scientific literature identified 5968 articles. After deduplication, screening of titles and abstracts, full-text review, and excluding incorrect populations and comparator, a total of 12 studies with 502 participants were included, of those 402 participants who had intra-arterial blood pressure measurement. Doppler mean arterial blood pressure showed a very high correlation with mean intra-arterial blood pressure (r = 0.97, r = 0.87) in low pulsatility situations. When the pulsatility was not evaluated, the correlation was high moderate (r = 0.63, r = 0.741). In low pulsatility situations, the correlation was moderate to high moderate (r = 0.42 to r = 0.65). Oscillometer automatic blood pressure cuff showed a moderate to very high correlation with intra-arterial mean arterial blood pressure (r = 0.42, r = 0.86) but also could be low in the context of low pulsatility associated with inconsistent success in noninvasive measurement (r = 0.25). Studies correlating intra-arterial with noninvasive techniques were performed in the context of routine clinical care using fluid-filled catheters. The degree of correlation between both methods is at least moderate.},
	doi = {10.1007/s10741-020-10006-4},
	pmid = {32696152 [Indexed for MEDLINE]}
}
